fn compute(n: u32) -> String {
    let div_part = {
        let mut s = String::new();
        if n % 3 == 0 {
            s.push_str("Foo");
        }
        if n % 5 == 0 {
            s.push_str("Bar");
        }
        if n % 7 == 0 {
            s.push_str("Qix");
        }
        s
    };

    let digit_part: String = n
        .to_string()
        .chars()
        .map(|c| match c {
            '3' => "Foo",
            '5' => "Bar",
            '7' => "Qix",
            _ => "",
        })
        .collect();

    let result = format!("{}{}", div_part, digit_part);
    if result.is_empty() {
        n.to_string()
    } else {
        result
    }
}

fn main() {
    for i in 1..=20 {
        println!("{} => {}", i, compute(i));
    }
}

